// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

contract VulnerableWallet {
    address public owner;

    constructor() { owner = msg.sender; }

    function withdraw(uint256 amount) external {
        require([[SLOT vuln_check]], "Not owner");
        (bool success, ) = owner.call{value: amount}("");
        require(success, "Transfer failed");
    }

    receive() external payable {}
}

contract SecureWallet {
    address public owner;
    error Unauthorized();

    constructor() {
        owner = msg.sender;
    }

    function withdraw(uint256 amount) external {
        [[SLOT secure_check]]
        (bool success, ) = owner.call{value: amount}("");
        require(success, "Transfer failed");
    }

    receive() external payable {}
}

contract PhishingAttack {
    function claim(address victim) external {
        VulnerableWallet(payable(victim)).withdraw(1 ether);
    }

    function claimSecure(address victim) external {
        SecureWallet(payable(victim)).withdraw(1 ether);
    }
}
